// Validar entrada y gestionar fallback
const content = $input.item.json.content || $('Edit Fields').item.json.content;
const failAttempts = $input.item.json.failAttempts || 0;

// Validar si es un solo dígito (0-9)
const isValidInput = /^[0-5]$/.test(content);

if (!isValidInput) {
  // Incrementar contador de intentos fallidos
  const newFailAttempts = failAttempts + 1;

  return {
    json: {
      conversation_id: $('Edit Fields').item.json.conversation_id,
      isValid: false,
      failAttempts: newFailAttempts,
      errorMessage: `⚠️ Opción no válida. Por favor, digita solo el número de la opción deseada (0-9).\n\n${newFailAttempts >= 2 ? '🤖 Te conectaré con el chat libre para ayudarte mejor.' : `Intentos: ${newFailAttempts}/2`}`
    }
  };
} else {
  // Entrada válida, resetear contador
  return {
    json: {
      conversation_id: $('Edit Fields').item.json.conversation_id,
      isValid: true,
      failAttempts: 0
    }
  };
}

